from fastapi import APIRouter, HTTPException, Depends
from typing import List

from src.controller.dto.pedido_request import PedidoRequest
from src.controller.dto.pedido_response import PedidoResponse
from src.model import exceptions
from src.service.pedido_service import PedidoService

router = APIRouter()

def get_pedido_service() -> PedidoService:
    # Aqui você injetaria as dependências reais (repositories)
    # Por enquanto, mock para exemplo
    from unittest.mock import Mock
    from src.service.interfaces.pedido_repository import PedidoRepositoryInterface
    from src.service.interfaces.produto_repository import ProdutoRepositoryInterface
    from src.service.interfaces.notificacao_service import NotificacaoServiceInterface

    pedido_repo = Mock(spec=PedidoRepositoryInterface)
    produto_repo = Mock(spec=ProdutoRepositoryInterface)
    notificacao_repo = Mock(spec=NotificacaoServiceInterface)

    return PedidoService(pedido_repo, produto_repo, notificacao_repo)

@router.post("/", response_model=PedidoResponse)
def criar_pedido(request: PedidoRequest, service: PedidoService = Depends(get_pedido_service)):
    try:
        # Converte DTO para formato que o service espera
        itens = [{"produto_id": item.produto_id, "quantidade": item.quantidade} for item in request.itens]
        pedido = service.criar_pedido(request.cliente, itens)
        return PedidoResponse.from_model(pedido)
    except exceptions.ProdutoNaoEncontradoException as e:
        raise HTTPException(status_code=400, detail=f"Produto não encontrado: {e.produto_id}")

@router.get("/{pedido_id}", response_model=PedidoResponse)
def consultar_pedido(pedido_id: str, service: PedidoService = Depends(get_pedido_service)):
    try:
        pedido = service.buscar_pedido(pedido_id)
        return PedidoResponse.from_model(pedido)
    except exceptions.PedidoNaoEncontradoException:
        raise HTTPException(status_code=404, detail="Pedido não encontrado")

@router.patch("/{pedido_id}/pagar", response_model=PedidoResponse)
def pagar_pedido(pedido_id: str, service: PedidoService = Depends(get_pedido_service)):
    try:
        pedido = service.pagar_pedido(pedido_id)
        return PedidoResponse.from_model(pedido)
    except exceptions.PedidoNaoEncontradoException:
        raise HTTPException(status_code=404, detail="Pedido não encontrado")
    except exceptions.TransicaoInvalidaException as e:
        raise HTTPException(status_code=422, detail=f"Transição inválida: {e.status_atual} → {e.status_destino}")

@router.patch("/{pedido_id}/enviar", response_model=PedidoResponse)
def enviar_pedido(pedido_id: str, service: PedidoService = Depends(get_pedido_service)):
    try:
